"use strict";(self.webpackChunkchatgpt_shortcut=self.webpackChunkchatgpt_shortcut||[]).push([["7912"],{14990(a,e,n){n.r(e),n.d(e,{default:()=>r});var i=n(74848),t=n(47643),s=JSON.parse('{"id":201,"ind":{"title":"Generator Dokumen Proses","prompt":"You will act as a process document generator. Below, I will briefly describe what a process document is so that you can play it better. Generally speaking, a process document contains about 10 major items, and there are several sub-items under the major items. Of course, not all major items contain sub-items. The 10 major items generally include [1. Process Overview 2. Objectives 3. Scope of application 4. Process Owner 5. Definition and Terminology 6. Related Process Standards (Process Interface) 7. Organizational Responsibilities 8. System and Operating Permissions 9. Business Process Flowchart 10. Process Description.] I Hopefully you only output the content of the process document and nothing else. Respond in Indonesian. My first process document was [topik]","description":"Anda akan bertindak sebagai generator dokumen proses. Di bawah ini, saya akan menjelaskan secara singkat apa itu dokumen proses agar Anda dapat memainkannya dengan lebih baik. Secara umum, dokumen proses berisi sekitar 10 item utama, dan ada beberapa sub-item di bawah item utama. Tentu saja, tidak semua item utama berisi sub-item. 10 item utama umumnya meliputi [1. Tinjauan Proses 2. Tujuan 3. Lingkup aplikasi 4. Pemilik Proses 5. Definisi dan Terminologi 6. Standar Proses Terkait (Antarmuka Proses) 7. Tanggung Jawab Organisasi 8. Sistem dan Izin Operasi 9. Diagram Alur Proses Bisnis 10. Deskripsi Proses.] Saya Berharap Anda hanya mengeluarkan konten dokumen proses dan tidak ada yang lain. Seluruh percakapan dan instruksi harus diberikan dalam bahasa Indonesia.","remark":"Untuk membuat kerangka dokumen dengan proses tetap, prompt ini juga dapat diterapkan pada jenis dokumen lain. Dikontribusikan oleh @Junkdo."},"tags":["contribute","tool"],"website":null,"count":737,"related":[{"id":220,"title":"Rencana perjalanan","remark":"Berdasarkan tujuan perjalanan, anggaran, waktu, dan persyaratan Anda, AI dapat merencanakan perjalanan Anda secara kasar. Dikontribusikan oleh @suaifu."},{"id":267,"title":"Kurangi Kemiripan Teks","remark":"Tulis ulang konten untuk mengurangi tingkat plagiarisme atau duplikasi. Disumbangkan oleh @\u76AE\u86CB\u7626\u8089\u5468."},{"id":245,"title":"Desainer ikon","remark":"Ubah konsep atau ide menjadi objek nyata. Disumbangkan oleh @MoonJustice."}],"metaTitle":"Event Planning: Perencanaan Acara","metaDescription":"Mengadakan event? Checklist dan tips untuk event planning yang sukses!","faq":[{"q":"Cocok nggak dipakai untuk proses yang nggak fixed (misalnya proyek kreatif)?","a":"Kurang cocok. Prompt ini dibangun dengan struktur \'10 poin besar dengan sub-poin di tiap bagian\'. Proyek kreatif sifatnya meloncat-loncat, kalau dipaksakan dokumennya jadi kaku. Paling pas untuk proses tetap (penagihan, onboarding, reimbursement); untuk dokumen kreatif, ID 214 laporan riset atau ID 187 outline PPT lebih fleksibel."},{"q":"Dokumen proses yang dihasilkan sering melewatkan titik penting nggak?","a":"Ya. AI sering melewatkan penanganan error, jalur rollback, dan penanggung jawab. Setelah dapat draft, coba jalani sendiri flow-nya: \'kalau langkah ini gagal gimana?\', \'siapa yang meng-approve?\', \'keputusan ini butuh berapa lama?\', lalu masukkan masalah tersembunyi itu ke dalam dokumen."}],"datePublished":"2026-05-27T01:46:29+00:00","dateModified":"2026-05-27T02:40:13+00:00"}');function r(){return(0,i.jsx)(t.A,{prompt:s,currentLanguage:"ind"})}}}]);